import { useState, useEffect, useCallback, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Slider } from "@/components/ui/slider";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useNavigationSettings, NavigationButton, NavigationSettings } from "@/hooks/useNavigationSettings";
import { Plus, Pencil, Trash2, GripVertical, Eye, EyeOff, Monitor, Tablet, Smartphone, Save, RotateCcw, Power, PowerOff, Link2 } from "lucide-react";
import { Alert, AlertDescription } from "@/components/ui/alert";
import * as LucideIcons from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useQueryClient } from "@tanstack/react-query";

const AVAILABLE_ICONS = [
  "MapPin", "List", "Calendar", "Map", "Store", "Home", "Search", "User", 
  "Settings", "Heart", "Star", "Bell", "ShoppingCart", "Gift", "Info", "HelpCircle"
];

type DeviceType = 'desktop' | 'tablet' | 'mobile';

interface DeviceStyleSettings {
  background_opacity: number;
  background_color: string;
  text_color: string;
  hover_bg_color: string;
  hover_text_color: string;
  shadow_enabled: boolean;
}

const AdminNavigationSettings = () => {
  const { t, i18n } = useTranslation();
  const queryClient = useQueryClient();
  const { settings, buttons, isLoading, updateSettings, createButton, updateButton, deleteButton } = useNavigationSettings();
  const [editingButton, setEditingButton] = useState<NavigationButton | null>(null);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [activeDeviceTab, setActiveDeviceTab] = useState<DeviceType>('desktop');
  const [formData, setFormData] = useState<Partial<NavigationButton>>({
    label_zh: "",
    label_en: "",
    label_pt: "",
    link: "",
    icon: "Circle",
    visible: true,
    enabled: true,
    show_on_desktop: true,
    show_on_tablet: true,
    show_on_mobile: true,
    show_when_logged_in: true,
    show_when_logged_out: true,
  });

  // Local state for style settings with preview - separate for each device
  const [desktopSettings, setDesktopSettings] = useState<DeviceStyleSettings>({
    background_opacity: 0,
    background_color: "transparent",
    text_color: "primary",
    hover_bg_color: "black",
    hover_text_color: "white",
    shadow_enabled: true,
  });
  const [tabletSettings, setTabletSettings] = useState<DeviceStyleSettings | null>(null);
  const [mobileSettings, setMobileSettings] = useState<DeviceStyleSettings | null>(null);
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);

  // Initialize local settings when settings load
  useEffect(() => {
    if (settings) {
      setDesktopSettings({
        background_opacity: settings.background_opacity ?? 0,
        background_color: settings.background_color || "transparent",
        text_color: settings.text_color || "primary",
        hover_bg_color: settings.hover_bg_color || "black",
        hover_text_color: settings.hover_text_color || "white",
        shadow_enabled: settings.shadow_enabled ?? true,
      });
      
      // Check if tablet has custom settings (any non-null value)
      if (settings.background_opacity_tablet !== null || 
          settings.background_color_tablet !== null ||
          settings.text_color_tablet !== null ||
          settings.hover_bg_color_tablet !== null ||
          settings.hover_text_color_tablet !== null ||
          settings.shadow_enabled_tablet !== null) {
        setTabletSettings({
          background_opacity: settings.background_opacity_tablet ?? settings.background_opacity ?? 0,
          background_color: settings.background_color_tablet || settings.background_color || "transparent",
          text_color: settings.text_color_tablet || settings.text_color || "primary",
          hover_bg_color: settings.hover_bg_color_tablet || settings.hover_bg_color || "black",
          hover_text_color: settings.hover_text_color_tablet || settings.hover_text_color || "white",
          shadow_enabled: settings.shadow_enabled_tablet ?? settings.shadow_enabled ?? true,
        });
      } else {
        setTabletSettings(null);
      }
      
      // Check if mobile has custom settings
      if (settings.background_opacity_mobile !== null || 
          settings.background_color_mobile !== null ||
          settings.text_color_mobile !== null ||
          settings.hover_bg_color_mobile !== null ||
          settings.hover_text_color_mobile !== null ||
          settings.shadow_enabled_mobile !== null) {
        setMobileSettings({
          background_opacity: settings.background_opacity_mobile ?? settings.background_opacity ?? 0,
          background_color: settings.background_color_mobile || settings.background_color || "transparent",
          text_color: settings.text_color_mobile || settings.text_color || "primary",
          hover_bg_color: settings.hover_bg_color_mobile || settings.hover_bg_color || "black",
          hover_text_color: settings.hover_text_color_mobile || settings.hover_text_color || "white",
          shadow_enabled: settings.shadow_enabled_mobile ?? settings.shadow_enabled ?? true,
        });
      } else {
        setMobileSettings(null);
      }
    }
  }, [settings]);

  const handleDeviceSettingChange = useCallback((device: DeviceType, key: keyof DeviceStyleSettings, value: any) => {
    if (device === 'desktop') {
      setDesktopSettings(prev => ({ ...prev, [key]: value }));
    } else if (device === 'tablet') {
      setTabletSettings(prev => prev ? { ...prev, [key]: value } : { ...desktopSettings, [key]: value });
    } else {
      setMobileSettings(prev => prev ? { ...prev, [key]: value } : { ...desktopSettings, [key]: value });
    }
    setHasUnsavedChanges(true);
  }, [desktopSettings]);

  const handleEnableDeviceCustomization = useCallback((device: DeviceType) => {
    if (device === 'tablet') {
      setTabletSettings({ ...desktopSettings });
    } else if (device === 'mobile') {
      setMobileSettings({ ...desktopSettings });
    }
    setHasUnsavedChanges(true);
  }, [desktopSettings]);

  const handleDisableDeviceCustomization = useCallback((device: DeviceType) => {
    if (device === 'tablet') {
      setTabletSettings(null);
    } else if (device === 'mobile') {
      setMobileSettings(null);
    }
    setHasUnsavedChanges(true);
  }, []);

  const handleSaveSettings = useCallback(() => {
    const updates: Partial<NavigationSettings> = {
      // Desktop settings
      background_opacity: desktopSettings.background_opacity,
      background_color: desktopSettings.background_color,
      text_color: desktopSettings.text_color,
      hover_bg_color: desktopSettings.hover_bg_color,
      hover_text_color: desktopSettings.hover_text_color,
      shadow_enabled: desktopSettings.shadow_enabled,
      // Tablet settings
      background_opacity_tablet: tabletSettings?.background_opacity ?? null,
      background_color_tablet: tabletSettings?.background_color ?? null,
      text_color_tablet: tabletSettings?.text_color ?? null,
      hover_bg_color_tablet: tabletSettings?.hover_bg_color ?? null,
      hover_text_color_tablet: tabletSettings?.hover_text_color ?? null,
      shadow_enabled_tablet: tabletSettings?.shadow_enabled ?? null,
      // Mobile settings
      background_opacity_mobile: mobileSettings?.background_opacity ?? null,
      background_color_mobile: mobileSettings?.background_color ?? null,
      text_color_mobile: mobileSettings?.text_color ?? null,
      hover_bg_color_mobile: mobileSettings?.hover_bg_color ?? null,
      hover_text_color_mobile: mobileSettings?.hover_text_color ?? null,
      shadow_enabled_mobile: mobileSettings?.shadow_enabled ?? null,
    };
    updateSettings.mutate(updates);
    setHasUnsavedChanges(false);
  }, [desktopSettings, tabletSettings, mobileSettings, updateSettings]);

  const handleResetSettings = useCallback(() => {
    if (settings) {
      setDesktopSettings({
        background_opacity: settings.background_opacity ?? 0,
        background_color: settings.background_color || "transparent",
        text_color: settings.text_color || "primary",
        hover_bg_color: settings.hover_bg_color || "black",
        hover_text_color: settings.hover_text_color || "white",
        shadow_enabled: settings.shadow_enabled ?? true,
      });
      
      if (settings.background_opacity_tablet !== null || settings.background_color_tablet !== null) {
        setTabletSettings({
          background_opacity: settings.background_opacity_tablet ?? settings.background_opacity ?? 0,
          background_color: settings.background_color_tablet || settings.background_color || "transparent",
          text_color: settings.text_color_tablet || settings.text_color || "primary",
          hover_bg_color: settings.hover_bg_color_tablet || settings.hover_bg_color || "black",
          hover_text_color: settings.hover_text_color_tablet || settings.hover_text_color || "white",
          shadow_enabled: settings.shadow_enabled_tablet ?? settings.shadow_enabled ?? true,
        });
      } else {
        setTabletSettings(null);
      }
      
      if (settings.background_opacity_mobile !== null || settings.background_color_mobile !== null) {
        setMobileSettings({
          background_opacity: settings.background_opacity_mobile ?? settings.background_opacity ?? 0,
          background_color: settings.background_color_mobile || settings.background_color || "transparent",
          text_color: settings.text_color_mobile || settings.text_color || "primary",
          hover_bg_color: settings.hover_bg_color_mobile || settings.hover_bg_color || "black",
          hover_text_color: settings.hover_text_color_mobile || settings.hover_text_color || "white",
          shadow_enabled: settings.shadow_enabled_mobile ?? settings.shadow_enabled ?? true,
        });
      } else {
        setMobileSettings(null);
      }
      
      setHasUnsavedChanges(false);
    }
  }, [settings]);

  const handleOpenDialog = (button?: NavigationButton) => {
    if (button) {
      setEditingButton(button);
      setFormData(button);
    } else {
      setEditingButton(null);
      setFormData({
        label_zh: "",
        label_en: "",
        label_pt: "",
        link: "",
        icon: "Circle",
        visible: true,
        enabled: true,
        show_on_desktop: true,
        show_on_tablet: true,
        show_on_mobile: true,
        show_when_logged_in: true,
        show_when_logged_out: true,
      });
    }
    setIsDialogOpen(true);
  };

  const autoTranslateLabel = async (text: string, sourceLang: string): Promise<{ zh: string; en: string; pt: string }> => {
    const targetLangs = ["zh", "en", "pt"].filter(l => l !== sourceLang);
    const results: Record<string, string> = { [sourceLang]: text };

    for (const targetLang of targetLangs) {
      try {
        const { data, error } = await supabase.functions.invoke("translate-content", {
          body: { text, targetLang },
        });
        results[targetLang] = (!error && data?.translatedText) ? data.translatedText.trim() : text;
      } catch {
        results[targetLang] = text;
      }
    }

    return { zh: results.zh || text, en: results.en || text, pt: results.pt || text };
  };

  const handleSaveButton = async () => {
    // Auto-translate the label to the other two languages
    const currentLang = i18n.language === "pt" ? "pt" : i18n.language === "zh" ? "zh" : "en";
    const inputLabel = formData[`label_${currentLang}` as keyof typeof formData] as string || "";

    if (inputLabel) {
      const translated = await autoTranslateLabel(inputLabel, currentLang);
      formData.label_zh = translated.zh;
      formData.label_en = translated.en;
      formData.label_pt = translated.pt;
    }

    if (editingButton) {
      await updateButton.mutateAsync({ id: editingButton.id, ...formData });
      
      // 如果是社区按钮且 enabled 状态变化，同步到网站设置
      if (editingButton.link === "/community" && editingButton.enabled !== formData.enabled) {
        await supabase
          .from("site_settings")
          .update({ 
            community_enabled: formData.enabled,
            updated_at: new Date().toISOString()
          })
          .limit(1);
        
        queryClient.invalidateQueries({ queryKey: ["site-settings"] });
      }
    } else {
      await createButton.mutateAsync({
        ...formData,
        sort_order: (buttons?.length || 0) + 1,
      } as any);
    }
    setIsDialogOpen(false);
  };

  const handleDeleteButton = async (id: string) => {
    if (confirm(t("admin.confirmDelete"))) {
      await deleteButton.mutateAsync(id);
    }
  };

  const getIconComponent = (iconName: string) => {
    const Icon = (LucideIcons as any)[iconName];
    return Icon ? <Icon className="w-4 h-4" /> : null;
  };

  const getLocalizedLabel = (button: NavigationButton) => {
    const lang = i18n.language;
    if (lang === "zh") return button.label_zh;
    if (lang === "pt") return button.label_pt;
    return button.label_en;
  };

  // Get current device settings for preview
  const getCurrentDeviceSettings = useCallback((device: DeviceType): DeviceStyleSettings => {
    if (device === 'desktop') return desktopSettings;
    if (device === 'tablet') return tabletSettings || desktopSettings;
    return mobileSettings || desktopSettings;
  }, [desktopSettings, tabletSettings, mobileSettings]);

  // Preview style computation
  const getPreviewStyle = useCallback((deviceSettings: DeviceStyleSettings) => {
    const bgOpacity = Number(deviceSettings.background_opacity || 0);
    const bgColor = deviceSettings.background_color || "transparent";
    
    let backgroundColor = "transparent";
    if (bgColor === "white") backgroundColor = `rgba(255,255,255,${bgOpacity})`;
    else if (bgColor === "black") backgroundColor = `rgba(0,0,0,${bgOpacity})`;
    else if (bgColor === "primary") backgroundColor = `rgba(var(--primary-rgb, 0,0,0),${bgOpacity})`;
    
    return { backgroundColor };
  }, []);

  const renderStyleSettings = (device: DeviceType, deviceSettings: DeviceStyleSettings) => (
    <div className="space-y-4">
      <div className="space-y-2">
        <Label>{t("admin.backgroundOpacity")}</Label>
        <div className="flex items-center gap-4">
          <Slider
            value={[Number(deviceSettings.background_opacity || 0) * 100]}
            onValueChange={(value) => handleDeviceSettingChange(device, "background_opacity", value[0] / 100)}
            max={100}
            step={5}
            className="flex-1"
          />
          <span className="w-12 text-right">{Math.round(Number(deviceSettings.background_opacity || 0) * 100)}%</span>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <Label>{t("admin.backgroundColor")}</Label>
          <Select
            value={deviceSettings.background_color || "transparent"}
            onValueChange={(value) => handleDeviceSettingChange(device, "background_color", value)}
          >
            <SelectTrigger>
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="transparent">{t("admin.transparent")}</SelectItem>
              <SelectItem value="white">{t("admin.white")}</SelectItem>
              <SelectItem value="black">{t("admin.black")}</SelectItem>
              <SelectItem value="primary">{t("admin.primary")}</SelectItem>
            </SelectContent>
          </Select>
        </div>

        <div className="space-y-2">
          <Label>{t("admin.textColor")}</Label>
          <Select
            value={deviceSettings.text_color || "primary"}
            onValueChange={(value) => handleDeviceSettingChange(device, "text_color", value)}
          >
            <SelectTrigger>
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="primary">{t("admin.primary")}</SelectItem>
              <SelectItem value="white">{t("admin.white")}</SelectItem>
              <SelectItem value="black">{t("admin.black")}</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <Label>{t("admin.hoverBgColor")}</Label>
          <Select
            value={deviceSettings.hover_bg_color || "black"}
            onValueChange={(value) => handleDeviceSettingChange(device, "hover_bg_color", value)}
          >
            <SelectTrigger>
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="black">{t("admin.black")}</SelectItem>
              <SelectItem value="white">{t("admin.white")}</SelectItem>
              <SelectItem value="primary">{t("admin.primary")}</SelectItem>
            </SelectContent>
          </Select>
        </div>

        <div className="space-y-2">
          <Label>{t("admin.hoverTextColor")}</Label>
          <Select
            value={deviceSettings.hover_text_color || "white"}
            onValueChange={(value) => handleDeviceSettingChange(device, "hover_text_color", value)}
          >
            <SelectTrigger>
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="white">{t("admin.white")}</SelectItem>
              <SelectItem value="black">{t("admin.black")}</SelectItem>
              <SelectItem value="primary">{t("admin.primary")}</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>

      <div className="flex items-center justify-between">
        <div>
          <Label>{t("admin.shadowEnabled")}</Label>
          <p className="text-sm text-muted-foreground">{t("admin.shadowEnabledDescription")}</p>
        </div>
        <Switch
          checked={deviceSettings.shadow_enabled ?? true}
          onCheckedChange={(checked) => handleDeviceSettingChange(device, "shadow_enabled", checked)}
        />
      </div>
    </div>
  );

  if (isLoading) {
    return <div className="p-6">{t("common.loading")}</div>;
  }

  return (
    <div className="space-y-6 p-6">
      <div>
        <h1 className="text-2xl font-bold">{t("admin.navigationSettings")}</h1>
        <p className="text-muted-foreground">{t("admin.navigationSettingsDescription")}</p>
      </div>

      {/* Live Preview */}
      <Card>
        <CardHeader>
          <CardTitle>{t("admin.preview")}</CardTitle>
        </CardHeader>
        <CardContent>
          <div 
            className="rounded-lg border overflow-hidden"
            style={{ backgroundColor: "#f0f0f0" }}
          >
            <div 
              className={`h-14 px-4 flex items-center justify-between ${getCurrentDeviceSettings(activeDeviceTab).shadow_enabled ? "shadow-[0_2px_4px_rgba(0,0,0,0.15)]" : ""}`}
              style={getPreviewStyle(getCurrentDeviceSettings(activeDeviceTab))}
            >
              <div className="w-8 h-8 rounded bg-primary/20" />
              <div className="flex gap-4">
                {buttons?.slice(0, 4).map((btn) => (
                  <span 
                    key={btn.id} 
                    className={`px-3 py-1 rounded text-sm ${
                      getCurrentDeviceSettings(activeDeviceTab).text_color === "white" ? "text-white" : 
                      getCurrentDeviceSettings(activeDeviceTab).text_color === "black" ? "text-black" : "text-primary"
                    }`}
                  >
                    {getLocalizedLabel(btn)}
                  </span>
                ))}
              </div>
              <div className="w-8 h-8 rounded-full bg-muted" />
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Navigation Bar Style Settings with Device Tabs */}
      <Card>
        <CardHeader className="flex flex-row items-center justify-between">
          <div>
            <CardTitle>{t("admin.navBarStyle")}</CardTitle>
            <CardDescription>{t("admin.navBarStyleDescription")}</CardDescription>
          </div>
          {hasUnsavedChanges && (
            <div className="flex gap-2">
              <Button variant="outline" size="sm" onClick={handleResetSettings}>
                <RotateCcw className="w-4 h-4 mr-2" />
                {t("common.reset")}
              </Button>
              <Button size="sm" onClick={handleSaveSettings} disabled={updateSettings.isPending}>
                <Save className="w-4 h-4 mr-2" />
                {t("common.save")}
              </Button>
            </div>
          )}
        </CardHeader>
        <CardContent>
          <Tabs value={activeDeviceTab} onValueChange={(v) => setActiveDeviceTab(v as DeviceType)}>
            <TabsList className="mb-4">
              <TabsTrigger value="desktop" className="gap-2">
                <Monitor className="w-4 h-4" />
                {t("admin.desktop")}
              </TabsTrigger>
              <TabsTrigger value="tablet" className="gap-2">
                <Tablet className="w-4 h-4" />
                {t("admin.tablet")}
              </TabsTrigger>
              <TabsTrigger value="mobile" className="gap-2">
                <Smartphone className="w-4 h-4" />
                {t("admin.mobile")}
              </TabsTrigger>
            </TabsList>

            <TabsContent value="desktop">
              {renderStyleSettings('desktop', desktopSettings)}
            </TabsContent>

            <TabsContent value="tablet">
              {tabletSettings ? (
                <div className="space-y-4">
                  <div className="flex items-center justify-between p-3 bg-muted/50 rounded-lg">
                    <span className="text-sm text-muted-foreground">
                      {t("admin.customTabletSettings")}
                    </span>
                    <Button 
                      variant="outline" 
                      size="sm"
                      onClick={() => handleDisableDeviceCustomization('tablet')}
                    >
                      {t("admin.useDesktopSettings")}
                    </Button>
                  </div>
                  {renderStyleSettings('tablet', tabletSettings)}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-8 text-center">
                  <Tablet className="w-12 h-12 text-muted-foreground mb-4" />
                  <p className="text-muted-foreground mb-4">
                    {t("admin.usingDesktopSettings")}
                  </p>
                  <Button onClick={() => handleEnableDeviceCustomization('tablet')}>
                    {t("admin.customizeTabletSettings")}
                  </Button>
                </div>
              )}
            </TabsContent>

            <TabsContent value="mobile">
              {mobileSettings ? (
                <div className="space-y-4">
                  <div className="flex items-center justify-between p-3 bg-muted/50 rounded-lg">
                    <span className="text-sm text-muted-foreground">
                      {t("admin.customMobileSettings")}
                    </span>
                    <Button 
                      variant="outline" 
                      size="sm"
                      onClick={() => handleDisableDeviceCustomization('mobile')}
                    >
                      {t("admin.useDesktopSettings")}
                    </Button>
                  </div>
                  {renderStyleSettings('mobile', mobileSettings)}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-8 text-center">
                  <Smartphone className="w-12 h-12 text-muted-foreground mb-4" />
                  <p className="text-muted-foreground mb-4">
                    {t("admin.usingDesktopSettings")}
                  </p>
                  <Button onClick={() => handleEnableDeviceCustomization('mobile')}>
                    {t("admin.customizeMobileSettings")}
                  </Button>
                </div>
              )}
            </TabsContent>
          </Tabs>
        </CardContent>
      </Card>

      {/* Navigation Buttons Management */}
      <Card>
        <CardHeader className="flex flex-row items-center justify-between">
          <div>
            <CardTitle>{t("admin.navButtons")}</CardTitle>
            <CardDescription>{t("admin.navButtonsDescription")}</CardDescription>
          </div>
          <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
            <DialogTrigger asChild>
              <Button onClick={() => handleOpenDialog()}>
                <Plus className="w-4 h-4 mr-2" />
                {t("admin.addButton")}
              </Button>
            </DialogTrigger>
            <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
              <DialogHeader>
                <DialogTitle>
                  {editingButton ? t("admin.editButton") : t("admin.addButton")}
                </DialogTitle>
              </DialogHeader>
              <div className="space-y-4 py-4">
                {/* Single language label - auto-translates to other languages on save */}
                <div className="space-y-2">
                  <Label>{t("admin.buttonLabel", "按钮标签")}</Label>
                  <Input
                    value={formData[`label_${i18n.language === "pt" ? "pt" : i18n.language === "zh" ? "zh" : "en"}` as keyof typeof formData] as string || ""}
                    onChange={(e) => {
                      const langKey = i18n.language === "pt" ? "label_pt" : i18n.language === "zh" ? "label_zh" : "label_en";
                      setFormData({ ...formData, [langKey]: e.target.value });
                    }}
                    placeholder={t("admin.buttonLabelPlaceholder", "输入按钮名称，保存时自动翻译")}
                  />
                  <p className="text-xs text-muted-foreground">
                    {t("admin.autoTranslateHint", "保存时将自动翻译为其他语言")}
                  </p>
                </div>

                {/* Link and Icon */}
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label>{t("admin.link")}</Label>
                    <Input
                      value={formData.link || ""}
                      onChange={(e) => setFormData({ ...formData, link: e.target.value })}
                      placeholder="/path"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label>{t("admin.icon")}</Label>
                    <Select
                      value={formData.icon || "Circle"}
                      onValueChange={(value) => setFormData({ ...formData, icon: value })}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        {AVAILABLE_ICONS.map((icon) => (
                          <SelectItem key={icon} value={icon}>
                            <div className="flex items-center gap-2">
                              {getIconComponent(icon)}
                              <span>{icon}</span>
                            </div>
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                {/* Device visibility */}
                <div className="space-y-2">
                  <Label>{t("admin.deviceVisibility")}</Label>
                  <div className="flex gap-4">
                    <div className="flex items-center gap-2">
                      <Switch
                        checked={formData.show_on_desktop ?? true}
                        onCheckedChange={(checked) => setFormData({ ...formData, show_on_desktop: checked })}
                      />
                      <Monitor className="w-4 h-4" />
                      <span className="text-sm">{t("admin.desktop")}</span>
                    </div>
                    <div className="flex items-center gap-2">
                      <Switch
                        checked={formData.show_on_tablet ?? true}
                        onCheckedChange={(checked) => setFormData({ ...formData, show_on_tablet: checked })}
                      />
                      <Tablet className="w-4 h-4" />
                      <span className="text-sm">{t("admin.tablet")}</span>
                    </div>
                    <div className="flex items-center gap-2">
                      <Switch
                        checked={formData.show_on_mobile ?? true}
                        onCheckedChange={(checked) => setFormData({ ...formData, show_on_mobile: checked })}
                      />
                      <Smartphone className="w-4 h-4" />
                      <span className="text-sm">{t("admin.mobile")}</span>
                    </div>
                  </div>
                </div>

                {/* Login state visibility */}
                <div className="space-y-2">
                  <Label>{t("admin.loginStateVisibility")}</Label>
                  <div className="flex gap-4">
                    <div className="flex items-center gap-2">
                      <Switch
                        checked={formData.show_when_logged_in ?? true}
                        onCheckedChange={(checked) => setFormData({ ...formData, show_when_logged_in: checked })}
                      />
                      <span className="text-sm">{t("admin.showWhenLoggedIn")}</span>
                    </div>
                    <div className="flex items-center gap-2">
                      <Switch
                        checked={formData.show_when_logged_out ?? true}
                        onCheckedChange={(checked) => setFormData({ ...formData, show_when_logged_out: checked })}
                      />
                      <span className="text-sm">{t("admin.showWhenLoggedOut")}</span>
                    </div>
                  </div>
                </div>

                {/* Feature Toggle (Enabled/Disabled) */}
                {formData.enabled === false && (
                  <Alert className="border-amber-200 bg-amber-50 dark:border-amber-900 dark:bg-amber-950">
                    <PowerOff className="h-4 w-4 text-amber-600" />
                    <AlertDescription className="text-amber-800 dark:text-amber-200">
                      {t("admin.featureDisabledWarning", "此功能已关闭，非管理员用户无法看到此导航按钮，也无法访问对应页面")}
                    </AlertDescription>
                  </Alert>
                )}
                
                {/* Community button sync hint */}
                {(editingButton?.link === "/community" || formData.link === "/community") && (
                  <Alert className="border-blue-200 bg-blue-50 dark:border-blue-900 dark:bg-blue-950">
                    <Link2 className="h-4 w-4 text-blue-600" />
                    <AlertDescription className="text-blue-800 dark:text-blue-200">
                      {t("admin.communityButtonSyncHint", "此按钮的开关状态与网站设置中的社区功能同步")}
                    </AlertDescription>
                  </Alert>
                )}
                
                <div className="flex items-center justify-between p-3 rounded-lg border bg-muted/30">
                  <div className="space-y-0.5">
                    <Label className="text-base font-medium flex items-center gap-2">
                      {formData.enabled !== false ? (
                        <Power className="w-4 h-4 text-green-500" />
                      ) : (
                        <PowerOff className="w-4 h-4 text-amber-500" />
                      )}
                      {t("admin.featureEnabled", "功能开关")}
                    </Label>
                    <p className="text-sm text-muted-foreground">
                      {formData.enabled !== false 
                        ? t("admin.featureEnabledDesc", "功能正常开放，用户可访问")
                        : t("admin.featureDisabledDesc", "功能已关闭，仅管理员可访问")}
                    </p>
                  </div>
                  <Switch
                    checked={formData.enabled !== false}
                    onCheckedChange={(checked) => setFormData({ ...formData, enabled: checked })}
                  />
                </div>

                {/* Visibility toggle */}
                <div className="flex items-center gap-2">
                  <Switch
                    checked={formData.visible ?? true}
                    onCheckedChange={(checked) => setFormData({ ...formData, visible: checked })}
                  />
                  <Label>{t("admin.visible")}</Label>
                </div>

                <div className="flex justify-end gap-2 pt-4">
                  <Button variant="outline" onClick={() => setIsDialogOpen(false)}>
                    {t("common.cancel")}
                  </Button>
                  <Button onClick={handleSaveButton} disabled={createButton.isPending || updateButton.isPending}>
                    {t("common.save")}
                  </Button>
                </div>
              </div>
            </DialogContent>
          </Dialog>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="w-12"></TableHead>
                <TableHead>{t("admin.status", "状态")}</TableHead>
                <TableHead>{t("admin.icon")}</TableHead>
                <TableHead>{t("admin.label")}</TableHead>
                <TableHead>{t("admin.link")}</TableHead>
                <TableHead>{t("admin.devices")}</TableHead>
                <TableHead>{t("admin.visible")}</TableHead>
                <TableHead className="text-right">{t("admin.actions")}</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {buttons?.map((button) => (
                <TableRow key={button.id} className={button.enabled === false ? "opacity-60" : ""}>
                  <TableCell>
                    <GripVertical className="w-4 h-4 text-muted-foreground cursor-move" />
                  </TableCell>
                  <TableCell>
                    <div title={button.enabled !== false ? t("admin.featureEnabled", "功能开启") : t("admin.featureDisabled", "功能关闭")}>
                      {button.enabled !== false ? (
                        <Power className="w-4 h-4 text-green-500" />
                      ) : (
                        <PowerOff className="w-4 h-4 text-amber-500" />
                      )}
                    </div>
                  </TableCell>
                  <TableCell>{getIconComponent(button.icon)}</TableCell>
                  <TableCell className="font-medium">{getLocalizedLabel(button)}</TableCell>
                  <TableCell className="text-muted-foreground">{button.link}</TableCell>
                  <TableCell>
                    <div className="flex gap-1">
                      {button.show_on_desktop && <Monitor className="w-4 h-4" />}
                      {button.show_on_tablet && <Tablet className="w-4 h-4" />}
                      {button.show_on_mobile && <Smartphone className="w-4 h-4" />}
                    </div>
                  </TableCell>
                  <TableCell>
                    {button.visible ? (
                      <Eye className="w-4 h-4 text-green-500" />
                    ) : (
                      <EyeOff className="w-4 h-4 text-muted-foreground" />
                    )}
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex justify-end gap-2">
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => handleOpenDialog(button)}
                      >
                        <Pencil className="w-4 h-4" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => handleDeleteButton(button.id)}
                      >
                        <Trash2 className="w-4 h-4 text-destructive" />
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </div>
  );
};

export default AdminNavigationSettings;
